<template><div class="page console-page"><header class="page-header"><div><div class="eyebrow">开发者中心</div><h1 class="page-title">快速开始</h1><p class="page-desc">使用当前环境真实网关、Virtual Key 和可访问服务模型生成 SDK 示例。</p></div><button class="btn" :disabled="loading" @click="check">检查服务</button></header><section class="quickstart-grid"><article class="card endpoint-card"><span class="eyebrow">实时连通性</span><h2>网关状态</h2><div v-if="loading" class="state-panel compact-state"><span class="loading-mark"></span>正在检查</div><div v-else-if="error" class="inline-alert danger">{{ error }}</div><div v-else-if="health" class="endpoint-status"><span class="status ok">可连接</span><code>{{ gatewayBase }}</code></div><div v-else class="state-panel empty-state compact-state">尚未检查网关</div></article><article class="card endpoint-card"><span class="eyebrow">真实访问范围</span><h2>选择 Virtual Key 可访问模型</h2><div class="field"><label>Virtual Key</label><input v-model="apiKey" class="input" type="password" autocomplete="off" placeholder="输入真实 Virtual Key"/></div><div class="field"><label>服务模型</label><a-select v-model:value="model" :options="models" :loading="modelsLoading" show-search option-filter-prop="label" placeholder="先查询可访问模型"/></div><button class="btn primary" :disabled="modelsLoading||!apiKey" @click="loadModels">查询模型</button><div v-if="modelError" class="inline-alert danger">{{ modelError }}</div><div v-else-if="modelsLoaded&&!models.length" class="state-panel empty-state compact-state">当前 Key 没有可访问模型</div></article></section><section class="card quickstart-code"><nav class="asset-tabs"><button v-for="item in examples" :key="item.key" :class="['asset-tab',{active:active===item.key}]" @click="active=item.key">{{ item.label }}</button></nav><div class="detail-heading"><div><span class="eyebrow">OpenAI Python SDK</span><strong>{{ current.label }}</strong></div><button class="btn" @click="copy">复制代码</button></div><pre class="code-block">{{ current.code }}</pre><div class="inline-alert">地址来自当前构建环境；页面不会保存 Virtual Key。模型选项只来自网关 <code>/v1/models</code>。</div></section></div></template>
<script setup lang="ts">import{computed,ref}from'vue';import axios from'axios';import{message}from'ant-design-vue';import{errorMessage,gatewayBase}from'../api/client';const loading=ref(false),error=ref(''),health=ref<any>(),apiKey=ref(''),model=ref<string>(),models=ref<{label:string,value:string}[]>([]),modelsLoading=ref(false),modelError=ref(''),modelsLoaded=ref(false),active=ref('chat');const selected=computed(()=>model.value||'YOUR_SERVICE_MODEL'),base=computed(()=>`${gatewayBase}/v1`);const examples=computed(()=>[{key:'chat',label:'Chat',code:`from openai import OpenAI\nclient = OpenAI(base_url="${base.value}", api_key="YOUR_VIRTUAL_KEY")\nresponse = client.chat.completions.create(\n    model="${selected.value}", messages=[{"role":"user","content":"你好"}]\n)\nprint(response.choices[0].message.content)`},{key:'stream',label:'Streaming',code:`from openai import OpenAI\nclient = OpenAI(base_url="${base.value}", api_key="YOUR_VIRTUAL_KEY")\nstream = client.chat.completions.create(\n    model="${selected.value}", messages=[{"role":"user","content":"你好"}], stream=True\n)\nfor chunk in stream:\n    print(chunk.choices[0].delta.content or "", end="")`},{key:'embedding',label:'Embedding',code:`from openai import OpenAI\nclient = OpenAI(base_url="${base.value}", api_key="YOUR_VIRTUAL_KEY")\nresult = client.embeddings.create(\n    model="${selected.value}", input=["需要向量化的真实文本"]\n)\nprint(len(result.data[0].embedding))`}]);const current=computed(()=>examples.value.find(item=>item.key===active.value)!);async function check(){loading.value=true;error.value='';health.value=undefined;try{health.value=(await axios.get(`${gatewayBase}/health`)).data}catch(e){error.value=errorMessage(e)}finally{loading.value=false}}async function loadModels(){modelsLoading.value=true;modelsLoaded.value=true;modelError.value='';model.value=undefined;try{const response=await axios.get(`${gatewayBase}/v1/models`,{headers:{Authorization:`Bearer ${apiKey.value}`}});models.value=(response.data?.data||[]).map((row:any)=>({label:row.id,value:row.id}))}catch(e){models.value=[];modelError.value=errorMessage(e)}finally{modelsLoading.value=false}}async function copy(){await navigator.clipboard.writeText(current.value.code);message.success('代码已复制')}</script>
